  1→{% extends "base.html" %}
  2→
  3→{% block title %}Dashboard - Maimai Assistant{% endblock %}
  4→
  5→{% block content %}
  6→<h2>Dashboard</h2>
  7→
  8→<div class="grid">
  9→    <article>
 10→        <header>Connection Status</header>
 11→        <p>Browser: <strong id="browser-status">--</strong></p>
 12→        <p>Login: <strong id="login-status">--</strong></p>
 13→        <p>CDP: <code id="cdp-endpoint">--</code></p>
 14→        <footer>
 15→            <button class="outline" onclick="checkStatus()">Refresh</button>
 16→        </footer>
 17→    </article>
 18→
 19→    <article>
 20→        <header>Task Queue</header>
 21→        <p>Queue size: <strong id="queue-size">0</strong></p>
 22→        <p>Current task: <strong id="current-task">None</strong></p>
 23→        <footer>
 24→            <a href="/search" role="button" class="outline">New Search</a>
 25→            <a href="/pipeline" role="button">New Pipeline</a>
 26→        </footer>
 27→    </article>
 28→</div>
 29→
 30→<h3>Recent Tasks</h3>
 31→<table id="recent-tasks">
 32→    <thead>
 33→        <tr>
 34→            <th>ID</th>
 35→            <th>Name</th>
 36→            <th>Status</th>
 37→            <th>Created</th>
 38→        </tr>
 39→    </thead>
 40→    <tbody>
 41→        <tr><td colspan="4">Loading...</td></tr>
 42→    </tbody>
 43→</table>
 44→{% endblock %}
 45→
 46→{% block scripts %}
 47→<script>
 48→async function checkStatus() {
 49→    try {
 50→        const [authRes, statusRes, tasksRes] = await Promise.all([
 51→            fetch('/api/auth/status'),
 52→            fetch('/api/status'),
 53→            fetch('/api/tasks?limit=10'),
 54→        ]);
 55→        const auth = await authRes.json();
 56→        const status = await statusRes.json();
 57→        const tasks = await tasksRes.json();
 58→
 59→        document.getElementById('browser-status').textContent = auth.browser_connected ? 'Connected' : 'Disconnected';
 60→        document.getElementById('browser-status').style.color = auth.browser_connected ? 'var(--pico-color-green-500)' : 'var(--pico-color-red-500)';
 61→        document.getElementById('login-status').textContent = auth.logged_in ? 'Logged in' : 'Not logged in';
 62→        document.getElementById('login-status').style.color = auth.logged_in ? 'var(--pico-color-green-500)' : 'var(--pico-color-red-500)';
 63→        document.getElementById('cdp-endpoint').textContent = auth.cdp_endpoint;
 64→
 65→        document.getElementById('queue-size').textContent = status.queue.queue_size;
 66→        document.getElementById('current-task').textContent = status.queue.current_task ? status.queue.current_task.name : 'None';
 67→
 68→        // Update connection badge
 69→        const badge = document.getElementById('connection-badge');
 70→        if (auth.browser_connected && auth.logged_in) {
 71→            badge.textContent = 'Online';
 72→            badge.dataset.status = 'ok';
 73→        } else if (auth.browser_connected) {
 74→            badge.textContent = 'Not Logged In';
 75→            badge.dataset.status = 'warn';
 76→        } else {
 77→            badge.textContent = 'Offline';
 78→            badge.dataset.status = 'error';
 79→        }
 80→
 81→        // Recent tasks
 82→        const tbody = document.querySelector('#recent-tasks tbody');
 83→        if (tasks.length === 0) {
 84→            tbody.innerHTML = '<tr><td colspan="4">No tasks yet</td></tr>';
 85→        } else {
 86→            tbody.innerHTML = tasks.map(t => `
 87→                <tr>
 88→                    <td><code>${t.task_id}</code></td>
 89→                    <td>${t.name}</td>
 90→                    <td><span class="badge" data-status="${t.status}">${t.status}</span></td>
 91→                    <td>${new Date(t.created_at).toLocaleString()}</td>
 92→                </tr>
 93→            `).join('');
 94→        }
 95→    } catch (e) {
 96→        console.error('Status check failed:', e);
 97→    }
 98→}
 99→
100→checkStatus();
101→setInterval(checkStatus, 10000);
102→</script>
103→{% endblock %}
104→

  1→{% extends "base.html" %}
  2→
  3→{% block title %}Candidates - Maimai Assistant{% endblock %}
  4→
  5→{% block content %}
  6→<h2>Candidates</h2>
  7→
  8→<div class="grid">
  9→    <input type="search" id="candidate-search" placeholder="Search by name, company, or title..." oninput="debouncedLoad()">
 10→    <button class="outline" onclick="exportCandidates()">Export Excel</button>
 11→</div>
 12→
 13→<table id="candidates-table">
 14→    <thead>
 15→        <tr>
 16→            <th>#</th>
 17→            <th>Name</th>
 18→            <th>Title</th>
 19→            <th>Company</th>
 20→            <th>Location</th>
 21→            <th>Messages</th>
 22→            <th>First Seen</th>
 23→        </tr>
 24→    </thead>
 25→    <tbody id="candidates-body">
 26→        <tr><td colspan="7">Loading...</td></tr>
 27→    </tbody>
 28→</table>
 29→
 30→<div id="pagination" class="pagination-controls"></div>
 31→{% endblock %}
 32→
 33→{% block scripts %}
 34→<script>
 35→let currentPage = 1;
 36→const pageSize = 20;
 37→
 38→async function loadCandidates(page = 1) {
 39→    currentPage = page;
 40→    const search = document.getElementById('candidate-search').value.trim();
 41→    const params = new URLSearchParams({page, page_size: pageSize});
 42→    if (search) params.append('search', search);
 43→
 44→    try {
 45→        const res = await fetch(`/api/candidates?${params}`);
 46→        const data = await res.json();
 47→        const tbody = document.getElementById('candidates-body');
 48→
 49→        if (!data.items.length) {
 50→            tbody.innerHTML = '<tr><td colspan="7">No candidates found</td></tr>';
 51→            document.getElementById('pagination').innerHTML = '';
 52→            return;
 53→        }
 54→
 55→        tbody.innerHTML = data.items.map((c, i) => `
 56→            <tr>
 57→                <td>${(page - 1) * pageSize + i + 1}</td>
 58→                <td>${escapeHtml(c.name || '--')}</td>
 59→                <td>${escapeHtml(c.title || '--')}</td>
 60→                <td>${escapeHtml(c.company || '--')}</td>
 61→                <td>${escapeHtml(c.location || '--')}</td>
 62→                <td>${c.message_count}</td>
 63→                <td>${c.first_seen ? new Date(c.first_seen).toLocaleDateString() : '--'}</td>
 64→            </tr>
 65→        `).join('');
 66→
 67→        // Pagination
 68→        const pag = document.getElementById('pagination');
 69→        let html = '';
 70→        if (page > 1) html += `<button class="outline" onclick="loadCandidates(${page-1})">Previous</button> `;
 71→        html += `<span>Page ${page} / ${data.total_pages} (${data.total} total)</span> `;
 72→        if (page < data.total_pages) html += `<button class="outline" onclick="loadCandidates(${page+1})">Next</button>`;
 73→        pag.innerHTML = html;
 74→    } catch (e) {
 75→        console.error('Failed to load candidates:', e);
 76→    }
 77→}
 78→
 79→let debounceTimer;
 80→function debouncedLoad() {
 81→    clearTimeout(debounceTimer);
 82→    debounceTimer = setTimeout(() => loadCandidates(1), 300);
 83→}
 84→
 85→async function exportCandidates() {
 86→    const search = document.getElementById('candidate-search').value.trim();
 87→    const res = await fetch('/api/export', {
 88→        method: 'POST',
 89→        headers: {'Content-Type': 'application/json'},
 90→        body: JSON.stringify({format: 'xlsx', search_keyword: search || null}),
 91→    });
 92→    const blob = await res.blob();
 93→    const url = URL.createObjectURL(blob);
 94→    const a = document.createElement('a');
 95→    a.href = url;
 96→    a.download = 'candidates.xlsx';
 97→    a.click();
 98→    URL.revokeObjectURL(url);
 99→}
100→
101→loadCandidates();
102→</script>
103→{% endblock %}
104→

 1→{% extends "base.html" %}
 2→
 3→{% block title %}Messages - Maimai Assistant{% endblock %}
 4→
 5→{% block content %}
 6→<h2>Message History</h2>
 7→
 8→<table id="messages-table">
 9→    <thead>
10→        <tr>
11→            <th>#</th>
12→            <th>Candidate</th>
13→            <th>Template</th>
14→            <th>Status</th>
15→            <th>Content</th>
16→            <th>Sent At</th>
17→        </tr>
18→    </thead>
19→    <tbody id="messages-body">
20→        <tr><td colspan="6">Loading...</td></tr>
21→    </tbody>
22→</table>
23→
24→<div id="msg-pagination" class="pagination-controls"></div>
25→{% endblock %}
26→
27→{% block scripts %}
28→<script>
29→let msgPage = 1;
30→const msgPageSize = 20;
31→
32→async function loadMessages(page = 1) {
33→    msgPage = page;
34→    try {
35→        // Use candidates endpoint to get message data via DB
36→        const res = await fetch(`/api/candidates?page=${page}&page_size=${msgPageSize}`);
37→        const data = await res.json();
38→
39→        // We need a messages-specific endpoint. For now, query candidates with messages.
40→        // TODO: Add /api/messages endpoint if needed
41→        const tbody = document.getElementById('messages-body');
42→
43→        // Load messages directly from the messages list approach
44→        const msgRes = await fetch(`/api/messages?page=${page}&page_size=${msgPageSize}`);
45→        if (msgRes.ok) {
46→            const msgData = await msgRes.json();
47→            if (!msgData.items || !msgData.items.length) {
48→                tbody.innerHTML = '<tr><td colspan="6">No messages yet</td></tr>';
49→                return;
50→            }
51→            tbody.innerHTML = msgData.items.map((m, i) => `
52→                <tr>
53→                    <td>${(page-1) * msgPageSize + i + 1}</td>
54→                    <td>${escapeHtml(m.candidate_name || m.candidate_maimai_id)}</td>
55→                    <td>${escapeHtml(m.template_name || '--')}</td>
56→                    <td><span class="badge" data-status="${m.status}">${m.status}</span></td>
57→                    <td title="${escapeHtml(m.content)}">${escapeHtml(m.content.substring(0, 60))}${m.content.length > 60 ? '...' : ''}</td>
58→                    <td>${m.sent_at ? new Date(m.sent_at).toLocaleString() : '--'}</td>
59→                </tr>
60→            `).join('');
61→
62→            // Pagination
63→            const pag = document.getElementById('msg-pagination');
64→            let html = '';
65→            if (page > 1) html += `<button class="outline" onclick="loadMessages(${page-1})">Previous</button> `;
66→            html += `<span>Page ${page} / ${msgData.total_pages} (${msgData.total} total)</span> `;
67→            if (page < msgData.total_pages) html += `<button class="outline" onclick="loadMessages(${page+1})">Next</button>`;
68→            pag.innerHTML = html;
69→        } else {
70→            tbody.innerHTML = '<tr><td colspan="6">Messages API not available</td></tr>';
71→        }
72→    } catch (e) {
73→        console.error('Failed to load messages:', e);
74→        document.getElementById('messages-body').innerHTML = '<tr><td colspan="6">Error loading messages</td></tr>';
75→    }
76→}
77→
78→loadMessages();
79→</script>
80→{% endblock %}
