  1→/**
  2→ * Pipeline page interaction logic.
  3→ * Handles form submission, progress tracking, candidate confirmation, and results display.
  4→ */
  5→
  6→let pipelineTaskId = null;
  7→let pipelineWS = null;
  8→let pipelineCandidates = [];
  9→
 10→document.getElementById('pipeline-form').addEventListener('submit', async (e) => {
 11→    e.preventDefault();
 12→    const form = e.target;
 13→
 14→    const keywords = form.keywords.value.split('\n').map(s => s.trim()).filter(Boolean);
 15→    const company = form.company.value.split('\n').map(s => s.trim()).filter(Boolean);
 16→    const template = form.template.value;
 17→    const pages = parseInt(form.pages.value) || 1;
 18→    const auto_send = form.auto_send.checked;
 19→    const dry_run = form.dry_run.checked;
 20→
 21→    if (!keywords.length) return alert('Please enter at least one keyword');
 22→    if (!template) return alert('Please select a template');
 23→
 24→    // Collect template variables
 25→    const variables = {};
 26→    form.querySelectorAll('[name^="var_"]').forEach(input => {
 27→        const key = input.name.replace('var_', '');
 28→        if (input.value.trim()) variables[key] = input.value.trim();
 29→    });
 30→
 31→    // Show progress, hide other sections
 32→    document.getElementById('pipeline-progress').hidden = false;
 33→    document.getElementById('pipeline-confirm').hidden = true;
 34→    document.getElementById('pipeline-results').hidden = true;
 35→    form.querySelector('button').disabled = true;
 36→
 37→    try {
 38→        const res = await fetch('/api/pipeline', {
 39→            method: 'POST',
 40→            headers: {'Content-Type': 'application/json'},
 41→            body: JSON.stringify({keywords, company, template, pages, variables, auto_send, dry_run}),
 42→        });
 43→        const data = await res.json();
 44→        pipelineTaskId = data.task_id;
 45→        document.getElementById('pipeline-task-id').textContent = data.task_id;
 46→
 47→        // Connect WebSocket for this task
 48→        pipelineWS = connectTaskWS(data.task_id, {
 49→            onEvent(msg) {
 50→                handlePipelineEvent(msg);
 51→            },
 52→            onComplete(msg) {
 53→                showPipelineResults(msg.result);
 54→                document.getElementById('pipeline-progress').hidden = true;
 55→                form.querySelector('button').disabled = false;
 56→            },
 57→            onError(msg) {
 58→                document.getElementById('pipeline-status-text').textContent = 'Failed';
 59→                document.getElementById('pipeline-detail').textContent = msg.error || 'Unknown error';
 60→                form.querySelector('button').disabled = false;
 61→            },
 62→        });
 63→
 64→        // Also start polling as fallback
 65→        pollTask(data.task_id, (task) => {
 66→            if (task.status === 'completed') {
 67→                showPipelineResults(task.result);
 68→                document.getElementById('pipeline-progress').hidden = true;
 69→                form.querySelector('button').disabled = false;
 70→                if (pipelineWS) pipelineWS.close();
 71→            }
 72→        }, 3000);
 73→
 74→    } catch (e) {
 75→        alert('Request failed: ' + e.message);
 76→        form.querySelector('button').disabled = false;
 77→        document.getElementById('pipeline-progress').hidden = true;
 78→    }
 79→});
 80→
 81→function handlePipelineEvent(msg) {
 82→    const statusEl = document.getElementById('pipeline-status-text');
 83→    const detailEl = document.getElementById('pipeline-detail');
 84→    const progressBar = document.getElementById('pipeline-progress-bar');
 85→
 86→    switch (msg.event) {
 87→        case 'search_progress':
 88→            statusEl.textContent = `Searching: ${msg.keyword} (${msg.keyword_index}/${msg.total_keywords})`;
 89→            break;
 90→
 91→        case 'search_keyword_done':
 92→            detailEl.textContent = `Found ${msg.found} candidates for "${msg.keyword}" (${msg.total_so_far} total)`;
 93→            break;
 94→
 95→        case 'search_complete':
 96→            statusEl.textContent = 'Search complete';
 97→            detailEl.textContent = `${msg.candidates.length} candidates found`;
 98→            break;
 99→
100→        case 'awaiting_confirmation':
101→            statusEl.textContent = 'Awaiting your confirmation';
102→            document.getElementById('pipeline-progress').hidden = true;
103→            showConfirmation(msg.candidates);
104→            break;
105→
106→        case 'sending_started':
107→            statusEl.textContent = 'Sending messages...';
108→            progressBar.max = msg.total;
109→            progressBar.value = 0;
110→            document.getElementById('pipeline-progress').hidden = false;
111→            document.getElementById('pipeline-confirm').hidden = true;
112→            break;
113→
114→        case 'send_progress':
115→            statusEl.textContent = `Sending: ${msg.current} (${msg.sent}/${msg.total})`;
116→            progressBar.value = msg.sent + msg.failed;
117→            progressBar.max = msg.total;
118→            detailEl.textContent = `Sent: ${msg.sent}, Failed: ${msg.failed}`;
119→            break;
120→
121→        case 'completed':
122→            showPipelineResults(msg.result);
123→            break;
124→
125→        default:
126→            detailEl.textContent = JSON.stringify(msg);
127→    }
128→}
129→
130→function showConfirmation(candidates) {
131→    pipelineCandidates = candidates;
132→    document.getElementById('pipeline-confirm').hidden = false;
133→    document.getElementById('confirm-count').textContent = candidates.length;
134→
135→    const list = document.getElementById('candidate-list');
136→    list.innerHTML = candidates.map(c => `
137→        <label>
138→            <input type="checkbox" value="${c.maimai_id}" checked>
139→            <span class="candidate-info">
140→                <span class="candidate-name">${escapeHtml(c.name)}</span>
141→                <span class="candidate-title">${escapeHtml(c.title)}</span>
142→                <span class="candidate-company">${escapeHtml(c.company)}</span>
143→            </span>
144→        </label>
145→    `).join('');
146→}
147→
148→function toggleSelectAll(checked) {
149→    document.querySelectorAll('#candidate-list input[type="checkbox"]').forEach(cb => {
150→        cb.checked = checked;
151→    });
152→}
153→
154→async function confirmCandidates(cancel = false) {
155→    if (!pipelineTaskId) return;
156→
157→    let maimai_ids = [];
158→    if (!cancel) {
159→        document.querySelectorAll('#candidate-list input[type="checkbox"]:checked').forEach(cb => {
160→            maimai_ids.push(cb.value);
161→        });
162→
163→        if (!maimai_ids.length) {
164→            return alert('Please select at least one candidate');
165→        }
166→    }
167→
168→    try {
169→        await fetch(`/api/pipeline/${pipelineTaskId}/confirm`, {
170→            method: 'POST',
171→            headers: {'Content-Type': 'application/json'},
172→            body: JSON.stringify({maimai_ids}),
173→        });
174→
175→        document.getElementById('pipeline-confirm').hidden = true;
176→        if (!cancel) {
177→            document.getElementById('pipeline-progress').hidden = false;
178→            document.getElementById('pipeline-status-text').textContent = 'Sending messages...';
179→        }
180→    } catch (e) {
181→        alert('Confirm failed: ' + e.message);
182→    }
183→}
184→
185→function showPipelineResults(result) {
186→    document.getElementById('pipeline-progress').hidden = true;
187→    document.getElementById('pipeline-confirm').hidden = true;
188→    document.getElementById('pipeline-results').hidden = false;
189→
190→    const summary = document.getElementById('results-summary');
191→
192→    if (!result || result.error) {
193→        summary.innerHTML = `<p>Error: ${result ? result.error : 'Unknown'}</p>`;
194→        return;
195→    }
196→
197→    if (result.dry_run) {
198→        summary.innerHTML = `
199→            <p>Dry run complete. Found <strong>${result.total}</strong> candidates.</p>
200→            <p>No messages were sent.</p>
201→        `;
202→        return;
203→    }
204→
205→    if (result.message) {
206→        summary.innerHTML = `<p>${escapeHtml(result.message)}</p>`;
207→        return;
208→    }
209→
210→    summary.innerHTML = `
211→        <div class="stat-grid">
