<script>
// --- Status bar (simplified from old index.html) ---
async function checkStatus() {
    try {
        const [authRes, statusRes] = await Promise.all([
            fetch('/api/auth/status'),
            fetch('/api/status'),
        ]);
        const auth = await authRes.json();
        const status = await statusRes.json();

        document.getElementById('browser-status').textContent = auth.browser_connected ? 'Connected' : 'Disconnected';
        document.getElementById('browser-status').style.color = auth.browser_connected ? 'var(--pico-color-green-500)' : 'var(--pico-color-red-500)';
        document.getElementById('login-status').textContent = auth.logged_in ? 'Logged in' : 'Not logged in';
        document.getElementById('login-status').style.color = auth.logged_in ? 'var(--pico-color-green-500)' : 'var(--pico-color-red-500)';
        document.getElementById('queue-size').textContent = status.queue.queue_size;

        const badge = document.getElementById('connection-badge');
        if (auth.browser_connected && auth.logged_in) {
            badge.textContent = 'Online';
            badge.dataset.status = 'ok';
