Key design decisions in this template:
- **No `dry_run` checkbox**: When `template` is empty (`value=""`), it is search-only mode. When template is selected, it is pipeline mode. The `dry_run` flag is derived automatically.
- **`auto_send` checkbox**: Only shown when template is selected (via `#messaging-options` fieldset).
- **Location field**: Added (was only in search.html, not pipeline.html).
- **Submit button text**: Dynamically changes between "Search" and "Start Pipeline".
- **Search results table**: Shown after search-only completes with the `showSearchResults()` function.
- **Pipeline results**: Shown after pipeline (send) completes with `showPipelineResults()`.

---

### Step 4: Rewrite `src/static/js/pipeline.js` -- Handle dual-mode

The current `pipeline.js` (235 lines) needs these changes:

**4a. Form submission logic** (replace lines 10-79):

The key change is that the form submission must decide whether to call `/api/search` or `/api/pipeline` based on whether a template is selected.

```javascript
document.getElementById('pipeline-form').addEventListener('submit', async (e) => {
    e.preventDefault();
    const form = e.target;

    const keywords = form.keywords.value.split('\n').map(s => s.trim()).filter(Boolean);
    const company = form.company.value.split('\n').map(s => s.trim()).filter(Boolean);
    const location = form.location.value.trim() || null;
    const pages = parseInt(form.pages.value) || 1;
    const template = form.template.value || null;  // null when "Search only"

    if (!keywords.length) return alert('Please enter at least one keyword');

    // Collect template variables
    const variables = {};
    form.querySelectorAll('[name^="var_"]').forEach(input => {
        const key = input.name.replace('var_', '');
        if (input.value.trim()) variables[key] = input.value.trim();
    });

    // Show progress, hide results
    document.getElementById('pipeline-progress').hidden = false;
    document.getElementById('pipeline-confirm').hidden = true;
    document.getElementById('pipeline-results').hidden = true;
    document.getElementById('search-results').hidden = true;
    form.querySelector('button').disabled = true;

    const isSearchOnly = !template;

    try {
        let res;
        if (isSearchOnly) {
            // Pure search mode -- use /api/search
            res = await fetch('/api/search', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({keywords, company, location, pages}),
            });
        } else {
            // Pipeline mode -- use /api/pipeline
            const auto_send = form.auto_send.checked;
            res = await fetch('/api/pipeline', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({
                    keywords, company, location, pages,
                    template, variables, auto_send, dry_run: false,
                }),
            });
        }

        const data = await res.json();
        pipelineTaskId = data.task_id;
        document.getElementById('pipeline-task-id').textContent = data.task_id;

        // Connect WebSocket
        pipelineWS = connectTaskWS(data.task_id, {
            onEvent(msg) {
                if (isSearchOnly) {
                    // Search events
                    document.getElementById('pipeline-status-text').textContent =
                        `${msg.event}: ${msg.keyword || ''} ${msg.found ? '(' + msg.found + ' found)' : ''}`;
                } else {
                    handlePipelineEvent(msg);
                }
            },
            onComplete(msg) {
                document.getElementById('pipeline-progress').hidden = true;
                form.querySelector('button').disabled = false;
                if (isSearchOnly) {
                    showSearchResults(msg.result || []);
                } else {
                    showPipelineResults(msg.result);
                }
            },
            onError(msg) {
                document.getElementById('pipeline-status-text').textContent = 'Failed';
                document.getElementById('pipeline-detail').textContent = msg.error || 'Unknown error';
                form.querySelector('button').disabled = false;
            },
        });

        // Polling fallback
        pollTask(data.task_id, (task) => {
            if (task.status === 'completed') {
                document.getElementById('pipeline-progress').hidden = true;
                form.querySelector('button').disabled = false;
                if (isSearchOnly) {
                    showSearchResults(task.result || []);
                } else {
                    showPipelineResults(task.result);
                }
                if (pipelineWS) pipelineWS.close();
            }
        }, 3000);

    } catch (e) {
        alert('Request failed: ' + e.message);
        form.querySelector('button').disabled = false;
        document.getElementById('pipeline-progress').hidden = true;
    }
});
```

